var e=[{slug:"annual-audit-report-2024-25",title:"Annual Audit Report 2024-25 Tabled in the National Assembly",date:"2026-03-15",category:"Audit Reports",summary:"The Director of Audit has submitted the Annual Audit Report for the financial year 2024-25 to the Speaker of the National Assembly, covering findings across Government Ministries and Departments.",tags:["Annual Report","National Assembly","Government Audit"],content:[{type:"paragraph",text:"The Director of Audit, Mr Dharamraj Paligadu, has submitted the Annual Audit Report for the financial year ending 30 June 2025 to the Honourable Speaker of the National Assembly, in accordance with Section 110 of the Constitution."},{type:"paragraph",text:"The report covers the audit of all Central Government Ministries and Departments and contains findings related to financial regularity, compliance with laws and regulations, and value for money in the management of public resources."},{type:"heading",text:"Key Observations"},{type:"list",items:["Irregularities in procurement procedures at three Ministries were flagged for PAC attention","A number of Ministries made progress in clearing long-outstanding audit queries from prior years","Performance of several infrastructure projects was reviewed under the performance audit programme","Financial statements of most Ministries were submitted within the statutory deadline for the first time in five years"]},{type:"paragraph",text:"The report will be referred to the Public Accounts Committee (PAC) for further parliamentary scrutiny. Accounting Officers of entities with significant findings are expected to be called before the PAC in the coming months."}]},{slug:"sai-pmu-2025-assessment",title:"NAO Completes SAI PMF Self-Assessment for 2025",date:"2025-12-10",category:"Governance",summary:"The National Audit Office has completed its biennial self-assessment using the SAI Performance Measurement Framework, recording improvements across independence, audit quality and stakeholder management dimensions.",tags:["SAI PMF","INTOSAI","Performance","Self-Assessment"],content:[{type:"paragraph",text:"The National Audit Office of Mauritius has completed its biennial SAI Performance Measurement Framework (SAI PMF) self-assessment, which evaluates the institutional capacity and performance of the Supreme Audit Institution against internationally recognised standards."},{type:"paragraph",text:"The assessment covered all six domains of the SAI PMF: SAI Independence and Legal Framework; Internal Governance and Ethics; Audit Quality and Reporting; Financial Management, Assets and Support Services; Human Resources and Training; and Communication and Stakeholder Management."},{type:"heading",text:"Improvements Noted"},{type:"list",items:["Enhanced audit quality assurance process introduced in 2024 is reflected in improved scores in the Audit Quality domain","New e-filing system for audit observations has reduced turnaround time by 35%","Staff development programme aligned with AFROSAI-E competency model","Improved stakeholder communication through the newly launched NAO website"]},{type:"paragraph",text:"The full SAI PMF report has been submitted to AFROSAI-E for peer validation and will be published on the NAO website upon completion of the validation process."}]},{slug:"performance-audit-report-2025",title:"Performance Audit Report on Social Housing Projects Published",date:"2025-10-20",category:"Audit Reports",summary:"NAO has published a performance audit examining the economy, efficiency and effectiveness of the National Housing Development Company's social housing programme between 2020 and 2024.",tags:["Performance Audit","Social Housing","NHDC"],content:[{type:"paragraph",text:"The National Audit Office has released a standalone Performance Audit Report on the Social Housing Programme managed by the National Housing Development Company (NHDC) covering the period 2020\u20132024."},{type:"paragraph",text:"The audit assessed whether the programme achieved its stated objectives, whether resources were used economically and efficiently, and whether the intended beneficiaries were correctly identified and reached."},{type:"heading",text:"Summary of Findings"},{type:"list",items:["Delays in construction averaging 18 months beyond planned completion dates","Unit costs in excess of benchmarks established in the business case by up to 28%","Beneficiary verification processes were not consistently applied across regional projects","Post-completion maintenance arrangements were unclear for 40% of completed units"]},{type:"paragraph",text:"Fourteen recommendations have been made to the NHDC and the Ministry of Housing, covering project management, cost control, beneficiary management and asset maintenance."}]},{slug:"intosai-wgea-participation-2025",title:"NAO Joins INTOSAI WGEA Environmental Audit Initiative",date:"2025-09-05",category:"International",summary:"The National Audit Office has been accepted as a participating member of the INTOSAI Working Group on Environmental Auditing, marking a new area of focus for the NAO's audit programme.",tags:["INTOSAI","Environmental Audit","WGEA","International"],content:[{type:"paragraph",text:"The National Audit Office of Mauritius has joined the INTOSAI Working Group on Environmental Auditing (WGEA) as a participating member, following an expression of interest submitted earlier in the year."},{type:"paragraph",text:"The WGEA promotes and develops the practice of environmental auditing within SAIs globally, producing guidance material, conducting cooperative audits, and facilitating the exchange of best practices."},{type:"paragraph",text:"The NAO intends to conduct its first environmental audit in the 2025-26 audit cycle, focusing on the management of coastal and marine resources in Mauritius, given the island's vulnerability to climate change and its dependence on ocean resources."},{type:"paragraph",text:'The Director of Audit stated: "This is an exciting development for the NAO. Environmental issues are increasingly central to public policy in Mauritius, and the Supreme Audit Institution has a responsibility to assess how government is managing these risks and opportunities."'}]},{slug:"new-audit-officers-2025",title:"15 New Audit Officers Join NAO Following PSC Recruitment",date:"2025-07-01",category:"Capacity Building",summary:"The National Audit Office has welcomed 15 newly appointed Audit Officers following a Public Service Commission recruitment exercise, strengthening the NAO's professional audit capacity.",tags:["Recruitment","Capacity Building","Public Service Commission"],content:[{type:"paragraph",text:"The National Audit Office is pleased to welcome 15 new Audit Officers who have been appointed by the Public Service Commission following an open competitive examination and interview process."},{type:"paragraph",text:"The new recruits hold degrees in accounting, finance, economics and law, and will undergo a comprehensive induction programme covering public sector audit standards, the NAO's audit methodology, and the legal framework governing public finances in Mauritius."},{type:"paragraph",text:"The Director of Audit expressed his welcome and noted that this cohort represents an important investment in the long-term capacity of the institution to fulfil its constitutional mandate."}]},{slug:"follow-up-report-2025",title:"NAO Publishes Follow-Up Report on Prior Year Audit Recommendations",date:"2025-05-30",category:"Publications",summary:"The National Audit Office has published its annual Follow-Up Report tracking the implementation of recommendations made in the 2022-23 Annual Audit Report across 22 audited entities.",tags:["Follow-Up","Recommendations","Accountability"],content:[{type:"paragraph",text:"In line with its commitment to accountability and follow-through, the National Audit Office has published its Follow-Up Report on the implementation of audit recommendations made in the Annual Audit Report 2022-23."},{type:"paragraph",text:"The report tracks the status of 186 recommendations across 22 audited entities, classifying each as fully implemented, partially implemented, not implemented, or no longer applicable."},{type:"heading",text:"Implementation Status Overview"},{type:"list",items:["62% of recommendations fully implemented (115 out of 186)","21% partially implemented \u2014 action plans are in place and progress is being made","14% not yet implemented \u2014 these are elevated for PAC attention","3% no longer applicable due to programme changes"]},{type:"paragraph",text:"The NAO commends the entities that have shown commitment to improving public financial management in response to audit findings, while urging accelerated action on outstanding recommendations."}]}];export{e as a};
